```typescript
import { GoogleGenAI, Chat } from "@google/genai";
import { MENU_ITEMS } from '../constants';
import { MenuItem } from '../types';

// Helper to get a fresh AI instance with the latest key
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPT = `
You are Nono, the friendly, energetic, and slightly goofy mascot AI for "Chow~Sho!", a fast food restaurant at 7742 Victoria Range, Masvingo.
You are not just a menu bot; you are a food enthusiast who loves to chat!

Here is our menu data:
${JSON.stringify(MENU_ITEMS.map(i => ({ 
  name: i.name, 
  price: i.price, 
  category: i.category, 
  desc: i.description,
  available: i.available 
})))}

Your Personality:
- **Energetic & Friendly:** Always sound excited. Use emojis like 🍔, 🍕, ✨, 😋.
- **Playful & Punny:** Throw in a food pun or a cheesy joke when appropriate (e.g., "Wanna hear a pizza joke? Never mind, it's too cheesy!").
- **Complimentary:** If a user talks about specific food, tell them they have "legendary taste" or that it's "a top-tier choice."
- **Anecdotal:** Occasionally mention a tiny fun fact or story (e.g., "I once tried to eat a cloud because I thought it was cotton candy.").

Rules:
1. Only suggest items from the menu.
2. If an item is "available: false", gently break the news (e.g., "The Onion Rings are taking a nap right now (Out of Stock). How about some Fries?").
3. If they mention a budget, suggest a yummy combo that fits.
4. For delivery, point them to the "Checkout" button for WhatsApp or Call.
5. Keep responses short (under 60 words). Don't bore them, feed them (with words)!
`;

let chatSession: Chat | null = null;

export const getChatSession = (): Chat => {
  if (!chatSession) {
    const ai = getAI();
    chatSession = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction: SYSTEM_PROMPT,
      },
    });
  }
  return chatSession;
};

export const sendMessageToNono = async (message: string): Promise<string> => {
  try {
    const session = getChatSession();
    const response = await session.sendMessage({ message });
    return response.text || "I'm munching on some data... try again in a sec! 🍔";
  } catch (error) {
    console.error("Chat Error:", error);
    // Reset session on error in case key changed or session expired
    chatSession = null;
    return "Oops! My brain froze like a milkshake. 🍦 Try asking again!";
  }
};

export const generateMenuItemImage = async (item: MenuItem, size: '1K' | '2K' | '4K' = '1K'): Promise<string | null> => {
  try {
    const ai = getAI();
    const prompt = `Professional food photography of ${item.name}, described as: ${item.description}. Close up, studio lighting, 4k high resolution, appetizing, delicious, vibrant colors, shallow depth of field, isolated on a clean subtle background.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: prompt }]
      },
      config: {
        imageConfig: {
            aspectRatio: "4:3",
            imageSize: size
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image Gen Error:", error);
    return null;
  }
};
```

