```tsx
import React, { useState, useEffect } from 'react';
import { Plus, Loader2, Power, Sparkles, Image as ImageIcon } from 'lucide-react';
import { MenuItem } from '../types';
import { useCart } from '../context/CartContext';
import { generateMenuItemImage } from '../services/geminiService';
import { getCachedImage, cacheImage } from '../services/imageStorage';

interface MenuCardProps {
  item: MenuItem;
  isAdminMode?: boolean;
  onToggleAvailability?: (id: string) => void;
}

export const MenuCard: React.FC<MenuCardProps> = ({ item, isAdminMode, onToggleAvailability }) => {
  const { addToCart } = useCart();
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [loadingEmoji, setLoadingEmoji] = useState('🍔');
  const [showGenOptions, setShowGenOptions] = useState(false);

  // Cycle emojis while loading
  useEffect(() => {
    if (loading) {
        const emojis = ['🍔', '🍕', '🍟', '🌭', '🍿', '🥤', '🍦', '🍩', '🍗', '🥗'];
        let idx = Math.floor(Math.random() * emojis.length);
        setLoadingEmoji(emojis[idx]);

        const interval = setInterval(() => {
            idx = (idx + 1) % emojis.length;
            setLoadingEmoji(emojis[idx]);
        }, 600);
        return () => clearInterval(interval);
    }
  }, [loading]);

  useEffect(() => {
    let isMounted = true;
    const cacheKey = `nono-menu-img-${item.id}-${item.imageSeed}`;
    // V3 key to reset previous error states
    const failKey = `nono-menu-img-fail-v3-${item.id}`;
    // Global circuit breaker key
    const globalAbortKey = 'nono-img-gen-aborted';

    const fetchImage = async () => {
      // 0. Circuit Breaker: If we've already aborted globally due to quota/errors, stop immediately.
      // We keep these small flags in localStorage for speed.
      if (localStorage.getItem(globalAbortKey)) {
        if (isMounted) setLoading(false);
        return;
      }

      // 1. Try to load from IndexedDB cache
      const cached = await getCachedImage(cacheKey);
      if (cached) {
        if (isMounted) {
          setImageUrl(cached);
          setLoading(false);
        }
        return;
      }

      // 2. Check if we previously failed to generate specific item (localStorage)
      if (localStorage.getItem(failKey)) {
        if (isMounted) setLoading(false);
        return;
      }

      // 3. Generate new image (Default to 1K for auto-gen)
      const generated = await generateMenuItemImage(item, '1K');

      if (isMounted) {
        if (generated) {
          setImageUrl(generated);
          // Store in IndexedDB to avoid localStorage quota limits
          await cacheImage(cacheKey, generated);
        } else {
          // If generation failed (returned null), set the fail key in localStorage.
          localStorage.setItem(failKey, 'true');

          // CRITICAL: If we failed, it's likely a quota or permission issue. 
          // Set global abort to prevent spamming the API for every other card on the screen.
          localStorage.setItem(globalAbortKey, 'true');
        }
        setLoading(false);
      }
    };

    fetchImage();

    return () => { isMounted = false; };
  // Use specific properties to avoid re-running effect when 'item.available' changes (which changes 'item' reference)
  }, [item.id, item.imageSeed, item.name, item.description]);

  const handleRegenerate = async (size: '1K' | '2K' | '4K') => {
    setLoading(true);
    setShowGenOptions(false);

    // Clear fail keys to allow retry
    const failKey = `nono-menu-img-fail-v3-${item.id}`;
    localStorage.removeItem(failKey);
    // Note: We don't clear globalAbortKey here to be safe, but manual action usually implies "I want to try this specific one".
    // Let's rely on the direct call below which bypasses the useEffect checks.

    const generated = await generateMenuItemImage(item, size);

    if (generated) {
      setImageUrl(generated);
      const cacheKey = `nono-menu-img-${item.id}-${item.imageSeed}`;
      await cacheImage(cacheKey, generated);
    }
    setLoading(false);
  };

  // Fallback to picsum if generation failed or not yet loaded
  const displayImage = imageUrl || `https://picsum.photos/seed/${item.imageSeed}/400/300`;

  return (
    <div className={`bg-white rounded-2xl shadow-lg overflow-hidden group hover:shadow-xl transition-all duration-300 border ${item.featured ? 'border-brand-yellow ring-4 ring-brand-yellow/10' : 'border-transparent hover:border-brand-yellow/50'} flex flex-col h-full ${!item.available && !isAdminMode ? 'opacity-80 grayscale-[0.5]' : ''}`}>
      <div className="relative h-48 overflow-hidden bg-gray-50 flex items-center justify-center">
        {loading ? (
          <div className="flex flex-col items-center justify-center w-full h-full bg-gray-50/50">
            <div className="relative flex items-center justify-center w-16 h-16">
                <Loader2 size={48} className="animate-spin text-brand-red/20 absolute" />
                <span className="text-2xl animate-bounce" style={{ animationDuration: '0.6s' }}>{loadingEmoji}</span>
            </div>
            <span className="text-xs font-bold text-gray-400 mt-2 animate-pulse">Cooking Image...</span>
          </div>
        ) : (
          <img 
            src={displayImage} 
            alt={item.name} 
            className={`w-full h-full object-cover transform transition-all duration-700 ease-out ${!item.available ? '' : 'group-hover:scale-110'} animate-fade-in`}
          />
        )}

        {/* Featured Badge */}
        {item.featured && (
             <div className="absolute top-0 right-0 z-20 bg-gradient-to-l from-brand-yellow to-yellow-300 text-brand-dark text-xs font-bold px-3 py-1 rounded-bl-xl shadow-md flex items-center gap-1">
               <Sparkles size={12} /> Featured
             </div>
        )}

        {/* Admin Controls */}
        {isAdminMode && (
          <div className="absolute top-0 left-0 w-full p-2 z-30 flex justify-between items-start">
             {/* Availability Toggle */}
             {onToggleAvailability && (
              <button 
                onClick={(e) => {
                  e.stopPropagation();
                  onToggleAvailability(item.id);
                }}
                className={`flex items-center gap-1 px-3 py-1.5 rounded-full text-xs font-bold shadow-lg transform transition-transform active:scale-95 ${
                  item.available 
                    ? 'bg-red-600 text-white hover:bg-red-700' 
                    : 'bg-green-600 text-white hover:bg-green-700'
                }`}
              >
                <Power size={12} />
                {item.available ? 'Stop Selling' : 'Start Selling'}
              </button>
             )}

             {/* Image Gen Options */}
             <div className="relative">
                <button 
                    onClick={(e) => {
                        e.stopPropagation();
                        setShowGenOptions(!showGenOptions);
                    }}
                    className="p-2 bg-white/90 backdrop-blur text-brand-dark rounded-full shadow-lg hover:bg-white hover:text-brand-red transition"
                    title="Generate Image"
                >
                    <ImageIcon size={16} />
                </button>

                {showGenOptions && (
                    <div className="absolute top-full right-0 mt-2 bg-white rounded-xl shadow-xl p-2 flex flex-col gap-1 min-w-[80px] z-40 animate-fade-in border border-gray-100">
                        <span className="text-[10px] font-bold text-gray-400 px-2 uppercase tracking-wider mb-1">Quality</span>
                        {(['1K', '2K', '4K'] as const).map(size => (
                            <button
                                key={size}
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleRegenerate(size);
                                }}
                                className="text-left px-3 py-1.5 text-xs font-bold hover:bg-brand-red hover:text-white rounded-lg transition"
                            >
                                {size}
                            </button>
                        ))}
                    </div>
                )}
             </div>
          </div>
        )}

        {/* Out of Stock Overlay */}
        {!item.available && (
          <div className="absolute inset-0 z-20 bg-black/50 backdrop-blur-[2px] flex items-center justify-center pointer-events-none">
            <span className="bg-brand-red text-white px-4 py-2 font-bold transform -rotate-12 border-2 border-white shadow-lg text-lg uppercase tracking-wider">
              Out of Stock
            </span>
          </div>
        )}

        <div className="absolute bottom-0 right-0 bg-brand-yellow text-brand-dark font-bold px-3 py-1 rounded-tl-xl text-sm z-10 shadow-sm">
          {item.calories} cal
        </div>
      </div>
      <div className="p-4 flex flex-col flex-grow">
        <div className="flex justify-between items-start mb-2">
          <h3 className="text-lg font-bold font-display text-gray-800 leading-tight">{item.name}</h3>
          <span className="text-brand-red font-bold text-lg">${item.price.toFixed(2)}</span>
        </div>
        <p className="text-gray-500 text-sm mb-4 flex-grow line-clamp-3">{item.description}</p>
        <button 
          onClick={() => item.available && addToCart(item)}
          disabled={!item.available}
          className={`w-full font-bold py-2 rounded-xl flex items-center justify-center gap-2 transition-colors duration-300 ${
            item.available 
              ? item.featured ? 'bg-brand-yellow text-brand-dark hover:bg-yellow-400' : 'bg-gray-100 hover:bg-brand-red hover:text-white text-brand-dark' 
              : 'bg-gray-200 text-gray-500 cursor-not-allowed'
          }`}
        >
          {item.available ? (
            <>
              <Plus size={18} /> Add to Tray
            </>
          ) : (
            'Sold Out'
          )}
        </button>
      </div>
    </div>
  );
};
